mapper.select:
select 
from exam_question


        and question_type = #{questionType}


        and exists (
            select 1
            from exam_question_course eqc
            where eqc.question_id = exam_question.id
            and eqc.course_id = #{courseId}
        )


        and difficulty = #{difficulty}


        and status = #{status}


        and question_content like concat('%', #{keyword}, '%')


order by id desc
